export const WILAYAS_BILINGUAL = Object.entries(WILAYAS_COMMUNES).map(([fr, info]) => ({
  fr,
  ar: info.ar,
}));

/** Get communes for a given wilaya (French name key) */
export function getCommunesForWilaya(wilayaFr: string): Commune[] {
  return WILAYAS_COMMUNES[wilayaFr]?.communes ?? [];
}
